import { useNavigate } from "react-router-dom";
import logo from "../logoa.png";

export default function AdminLogin() {
  const navigate = useNavigate();

  const handleLogin = () => {
    navigate("/dashboard");
  };

  return (
    <div
      className="min-h-screen flex flex-col items-center justify-center bg-cover bg-center relative"
      style={{
        backgroundImage:
          "linear-gradient(rgba(8,28,60,0.9), rgba(8,28,60,0.9)), url('/crane.jpg')",
      }}
    >
      {/* Logo */}
      <img 
  src={logo} 
  alt="Logo" 
  style={{ width: "500px", height: "auto", marginBottom: "20px" }} 
/>
      <div className="text-center mb-8">
        
      </div>

      {/* Subtitle */}
      <p className="text-gray-300 mb-8 text-center max-w-md">
        Sign in to access your construction management system
      </p>

      {/* Login Card */}
      <div className="bg-white/10 backdrop-blur-lg border border-white/20 rounded-2xl p-8 w-[400px] shadow-2xl">
        <div className="mb-5">
          <label className="block text-gray-200 mb-2">
            Username
          </label>
          <input
            type="text"
            placeholder="Enter your username"
            className="w-full px-4 py-3 rounded-xl bg-white/10 border border-white/20 text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-400"
          />
        </div>

        <div className="mb-6">
          <label className="block text-gray-200 mb-2">
            Password
          </label>
          <input
            type="password"
            placeholder="Enter your password"
            className="w-full px-4 py-3 rounded-xl bg-white/10 border border-white/20 text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-400"
          />
        </div>

        <button
          onClick={handleLogin}
          className="w-full bg-orange-500 hover:bg-orange-600 transition duration-300 text-white py-3 rounded-xl font-semibold shadow-lg"
        >
          Sign In
        </button>
      </div>
    </div>
  );
}
